member.example:
Bind the LineRenderer color property using a serialized binder field — the target LineRenderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LineRendererColorBinder _lineColor;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _lineColor;
    }


Bind the LineRenderer color property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LineRenderer _lineRenderer;
        
        private LineRendererColorBinder LineColor =>
            new(_lineRenderer);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Color _lineColor;
    }

Switch the LineRenderer color between two values using a serialized binder field — the target LineRenderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LineRendererColorSwitcherBinder _isHighlighted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }


Switch the LineRenderer color between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LineRenderer _lineRenderer;
        
        private LineRendererColorSwitcherBinder IsHighlighted => new(
            _lineRenderer, Color.yellow, Color.white);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }
